var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"가지 마.","JPN":"行かないで。","ENG":"Don't go.","TWN":"別去。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"직원 한 명이 무사한지 알아보려고 북방합의체에 직접 발을 들인다니. 리스크가 너무 커.","JPN":"職員1人の無事を確認するために、北方合意体に直接侵入するなんて。リスクが大きすぎる。","ENG":"It's just too risky for you to step foot into the Northern Union to find out if one of your employees is safe.","TWN":"為了確認一名員工的安全，親自踏入北方和議會領土。這其中的風險太大了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나 혼자 가는 건 아닐세. 하지만 내가 빠질 수는 없어.","JPN":"私1人で行くわけではない。だが、私が行かないわけにはいかない。","ENG":"I'm not going alone. But I must be there.","TWN":"放心，我不是一個人。而且我絕對不能缺席。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자가 목숨을 걸어야 할 일이라면 차라리 포기해. 고작 연락이 안 닿을 뿐인 거잖아.","JPN":"最高管理者が命をかけるほどのことなら、いっそ諦めたら。別に連絡が取れないだけじゃない。","ENG":"If it's something the Supreme Administrator has to risk his life for, then I suggest you just let it go. It's just we've lost contact with him.","TWN":"如果連最高管理者都必須拼命的事情，那還不如放棄算了。現在只是聯絡不上而已啊。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"합의체가 관리국을 어떻게 대할지 몰라서 그러는 거야?","JPN":"合意体が管理局にどんな態度を取るのかわからないわけじゃないよね？","ENG":"You know how the Northern Union treats the Administration, right?","TWN":"你難道不知道北方和議會是怎麼對待管理局的嗎……？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"날 걱정해주는 건가?","JPN":"私を心配してくれるのか？","ENG":"Are you worried about me?","TWN":"你是在擔心我嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그야 당연하지!","JPN":"当たり前でしょ！","ENG":"Of course, I am!","TWN":"那當然。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자가 인질로 잡혔다간, 안 그래도 당신 때문에 떨어진 관리국의 체면과 신뢰가 더 바닥으로 곤두박질 칠 테니까!","JPN":"最高管理者が人質にでもなったら、ただでさえあなたのせいでガタ落ちになった管理局の面子と信頼は地の底まで落ちちゃうだろうから！","ENG":"If the Supreme Administrator is taken hostage, the Administration's reputation and credibility will crash! All because of you!","TWN":"最高管理者被劫持的話，本來就因為你而下降的管理局顏面和信譽會更加跌到谷底的！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직원이라고 말은 했지만, 곧 다가올 클리포트 게임에 반드시 필요한 전력일세.","JPN":"職員と言っているが、目前に迫っているクリフォトゲームに必ず必要な戦力だ。","ENG":"I said that it was an employee of mine, but she's also a key factor I need for the next Qliphoth Game.","TWN":"說是說員工，但她也是即將到來的逆卡巴拉遊戲中必不可少的戰力。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 직원에게 문제가 생겼다면 무리를 해서라도 데려와야지.","JPN":"その職員に問題が起こったのなら、無理をしてでも連れてくるべきさ。","ENG":"So, if something has happened to her, I must do whatever I can to bring her back.","TWN":"如果那位員工遇到困難，就算拼命也要把她帶回來。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하아, 난 경고할 만큼 했어.","JPN":"はあ、私は警告したからね。","ENG":"*Sigh* I warned you.","TWN":"欸……我已經警告過了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"방송에 당신 피랍소식이 뜨는 순간 시니어는 때려치우고 이직할 거니까 알아서 해.","JPN":"テレビであなたの拉致ニュースが出た瞬間、シニアはやめて転職するから。もう好きにして。","ENG":"Just know that the moment I see news of your kidnapping, I'm going to quit my job as a Senior and find a different job.","TWN":"一旦你的被綁架的消息出現在新聞裡，我就會辭職跳槽，所以你自己看著辦吧。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 일은 없도록 조심하지.","JPN":"そうならないように気をつけるさ。","ENG":"I'll be careful not to let that happen.","TWN":"我會小心，不會讓那種事發生的。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 다녀오겠네.","JPN":"では、行ってくるよ。","ENG":"Then, I'll be back before you know it.","TWN":"那我走了。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내 연락책도 한 명 데려가.","JPN":"私の連絡役も1人連れて行って。","ENG":"Take one of my contacts with you too.","TWN":"帶上我的聯絡人。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이 뭘 하고 돌아다니는 건지, 시니어인 나에게도 알 권리가 있으니까.","JPN":"あなたが何をしながら歩き回ってるのか、シニアの私にも知る権利があるからね。","ENG":"I have a right to know what you are up to as a Senior.","TWN":"你在外面做什麼，我作為Senior也有權知道。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"연락책?","JPN":"連絡役？","ENG":"Contact?","TWN":"聯絡人？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"정식으로 인사드리죠.","JPN":"正式にご挨拶申し上げます。","ENG":"Pleased to meet you, sir.","TWN":"正式向你問好。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NONAME","text":{"KOREA":"로터스 경호국장 파티마입니다. 최고관리자님의 호위를 맡게 되어 영광입니다.","JPN":"ロータスの警護局長、ファティマです。最高管理者様の護衛を担当することになり、光栄です。","ENG":"I am Fatima, Chief of Lotus' security. It is an honor to serve as your bodyguard.","TWN":"我是洛德斯警衛局的局長，法蒂瑪。能夠擔任最高管理者的保鑣是我的榮幸。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"편하게, 파티마라고 불러주십시오.","JPN":"ファティマとお呼びください。","ENG":"Please feel free to address me as Fatima.","TWN":"請叫我法蒂瑪就好。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"합의체와의 마찰을 피하기 위해 관리국 인원은 쓰지 않기로 한 거 아니었나?","JPN":"合意体とのもめごとを避けるために、管理局の人員を使わないことにしたわけではなかったのか？","ENG":"Didn't you say you didn't want to use any of the Administration's personnel to avoid any conflict with the Northern Union?","TWN":"不是說為了避免與北方和議會發生衝突，不使用管理局的人嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이미 최고관리자가 그 영토에 발을 들이기로 한 마당에 그런 게 무슨 의미가 있겠어?","JPN":"すでに最高管理者がその領土に足を踏み入れると決めた今、そんなことに何の意味がある？","ENG":"That's been thrown out the window when the Supreme Administrator said that he'd go there himself.","TWN":"你這個最高管理者都已經自己去了，現在說這些還有什麼意義？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"일부러 합의체 녀석들 눈에 띄지만 마.","JPN":"合意体のやつらの目につかないようにしてよ。","ENG":"Just don't try to get their attention, okay?","TWN":"別故意引起那幫人的注意，好嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 수행원을 데려가도 괜찮은 건가? 스완이 언제 자넬 노리러 올 지 모르는데.","JPN":"君の随行員を連れて行ってもいいのかね？　スワンがいつ君を狙ってくるかわからないんだぞ。","ENG":"Is it okay for me to take your bodyguard with me? What if Swan comes after you?","TWN":"但把你的屬下帶走沒問題嗎？不知道史旺會不會找過來？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};